void init(void) {
  printf("%s | INIT!\n", microkit_name);

  sb_queue_TempControl_SysVerif_Temperature_1_Recv_init(&tsp_tst_currentTemp_recv_queue, (sb_queue_TempControl_SysVerif_Temperature_1_t *) tsp_tst_currentTemp_queue_1);

  sb_queue_TempControl_SysVerif_FanCmd_1_Recv_init(&tcp_tct_fanCmd_recv_queue, (sb_queue_TempControl_SysVerif_FanCmd_1_t *) tcp_tct_fanCmd_queue_1);

  sb_queue_TempControl_SysVerif_FanAck_1_Recv_init(&fp_ft_fanAck_recv_queue, (sb_queue_TempControl_SysVerif_FanAck_1_t *) fp_ft_fanAck_queue_1);

  sb_queue_TempControl_SysVerif_SetPoint_1_Recv_init(&tcp_tct_setPoint_recv_queue, (sb_queue_TempControl_SysVerif_SetPoint_1_t *) tcp_tct_setPoint_queue_1);

  sb_queue_hamr_SchedState_1_Recv_init(&sched_state_recv_queue, (sb_queue_hamr_SchedState_1_t *) sched_state_queue_1);

  sb_queue_hamr_Schedule_1_Recv_init(&sched_schedule_recv_queue, (sb_queue_hamr_Schedule_1_t *) sched_schedule_queue_1);

  userland_monitor_process_userland_monitor_thread_initialize();

  microkit_notify(PORT_FROM_MON);
}

void notified(microkit_channel channel) {
  switch (channel) {
    case PORT_FROM_MON:
      userland_monitor_process_userland_monitor_thread_timeTriggered();
      break;
    default:
      userland_monitor_process_userland_monitor_thread_notify(channel);
  }
}
